parameters.jsCode:
const raw = $input.first().json.choices[0].message.content.trim();
let cleaned = raw;
if (cleaned.startsWith('```')) {
  cleaned = cleaned.split('```')[1];
  if (cleaned.startsWith('json')) cleaned = cleaned.slice(4);
}
const lesson = JSON.parse(cleaned.trim());

const words = lesson.words;
let wordsText = '';
for (let i = 0; i < words.length; i++) {
  const w = words[i];
  wordsText += `${i+1}. *${w.word}* \`${w.transcription}\`\n`;
  wordsText += `   🇺🇦 ${w.translation}\n`;
  wordsText += `   💬 _${w.example}_\n`;
  wordsText += `   _${w.example_ua}_\n\n`;
}

const idiom = lesson.idiom;
const days = ['Неділя','Понеділок','Вівторок','Середа','Четвер','П\'ятниця','Субота'];
const dayName = days[new Date().getDay()];

const text = `📚 *Урок дня — ${dayName}*\n━━━━━━━━━━━━━━━━━\n\n${wordsText}💬 *Idiom дня:*\n_${idiom.text}_ — ${idiom.translation}\n💡 _${idiom.example}_\n\n📖 *Mini-story:*\n_${lesson.mini_story}_\n_${lesson.mini_story_ua}_\n\n✏️ Вивчи слова → /today\n🧠 Пройди тест → /quiz\n🏆 Перевір рейтинг → /top`;

return [{ json: { text } }];
